public boolean _add(Annotation ann) {
    if (_annotations == null) {
        _annotations = new HashMap<Class<? extends Annotation>,Annotation>();
    }
    if (ann == null) {
        return false;
    }
    Class<? extends Annotation> annType = ann.annotationType();
    if (_annotations.containsKey(annType)) {
        return false;
    }
    _annotations.put(annType, ann);
    return true;
}
